<script setup lang="ts">
import { Head } from '@inertiajs/vue3';
import { BarChart3, Check, Crown, Download, Radio, Rocket, ShieldCheck, Sparkles, Users } from '@lucide/vue';
import { computed, onMounted, ref } from 'vue';
import AppShell from '../../Layouts/AppShell.vue';

type Plan={id:number;name:string;slug:string;tagline:string;description:string;monthly_price_cents:number;annual_price_cents:number;features:string[];limits:Record<string,any>;accent:string;is_featured:boolean};
const props=defineProps<{plans:Plan[];currentPlan:string;membership:any;scheduledPlan:any}>();
const annual=ref(props.membership?.billing_interval==='annual'),saving=ref<string|null>(null),notice=ref(''),error=ref('');
const price=(plan:Plan)=>annual.value?plan.annual_price_cents:plan.monthly_price_cents;
const monthlyEquivalent=(plan:Plan)=>annual.value?Math.round(plan.annual_price_cents/12):plan.monthly_price_cents;
const money=(cents:number)=>new Intl.NumberFormat('en-ZA',{style:'currency',currency:'ZAR',maximumFractionDigits:0}).format(cents/100);
const current=computed(()=>props.plans.find(plan=>plan.slug===props.currentPlan));
const csrf=()=>document.querySelector<HTMLMetaElement>('meta[name="csrf-token"]')?.content??'';
const openCheckout=(checkout:any)=>{const form=document.createElement('form');form.method=checkout.method||'POST';form.action=checkout.action;Object.entries(checkout.fields??{}).forEach(([name,value])=>{const input=document.createElement('input');input.type='hidden';input.name=name;input.value=String(value??'');form.appendChild(input)});document.body.appendChild(form);form.submit()};
const changePlan=async(plan:Plan)=>{if(plan.slug===props.currentPlan)return;if(plan.monthly_price_cents===0&&!confirm('Move to Free at the end of your current paid period? You will keep your paid benefits until then.'))return;saving.value=plan.slug;notice.value='';error.value='';try{const response=await fetch(`/api/v1/membership/plans/${plan.slug}/checkout`,{method:'POST',credentials:'same-origin',headers:{Accept:'application/json','Content-Type':'application/json','X-CSRF-TOKEN':csrf()},body:JSON.stringify({billing_interval:annual.value?'annual':'monthly'})});const payload=await response.json();if(!response.ok)throw new Error(payload.message||'We could not start this plan change.');const result=payload.data??payload;if(result.checkout){openCheckout(result.checkout);return}notice.value=result.scheduled?'Your downgrade is scheduled. Your current benefits remain active until the end of the paid period.':'Your membership has been changed.';setTimeout(()=>location.reload(),1200)}catch(exception:any){error.value=exception.message}finally{saving.value=null}};
onMounted(()=>{const payment=new URLSearchParams(location.search).get('payment');if(payment==='processing')notice.value='PayFast has returned your payment. We are confirming it securely and will activate your plan shortly.';if(payment==='cancelled')error.value='The PayFast payment was cancelled. No plan changes were made.'});
</script>

<template>
  <Head title="Membership"/><AppShell><main class="membership-page">
    <p v-if="notice" class="membership-message success">{{notice}}</p><p v-if="error" class="membership-message error">{{error}}</p>
    <section class="membership-intro"><div class="intro-copy"><span><Crown/> MEMBERSHIP</span><h1>Choose the space<br/>your sport needs.</h1><p>Every plan starts with the complete SportsUniverse experience. Upgrade only when you need more reach, intelligence and professional capacity.</p></div><aside class="membership-account"><div><small>YOUR MEMBERSHIP</small><span>Active</span></div><strong>{{current?.name||'Free'}}</strong><p>{{scheduledPlan?`${scheduledPlan.name} begins ${new Date(scheduledPlan.starts_at).toLocaleDateString('en-ZA')}`:current?.tagline}}</p><a href="#plans">Compare your plan <span>↓</span></a></aside></section>
    <section class="membership-signals" aria-label="Membership highlights"><div><Radio/><span><strong>1K–100K</strong><small>Live audience capacity</small></span></div><div><BarChart3/><span><strong>Built to grow</strong><small>Analytics that scale with you</small></span></div><div><ShieldCheck/><span><strong>No lost progress</strong><small>Your profile always stays intact</small></span></div></section>
    <div class="billing-switch"><button :class="{active:!annual}" @click="annual=false">Monthly</button><button :class="{active:annual}" @click="annual=true">Yearly <b>2 months free</b></button></div>
    <section v-if="!plans.length" class="membership-plans-empty"><ShieldCheck/><div><strong>Membership plans are being prepared</strong><p>Free, Pro and Elite are temporarily unavailable. Please try again shortly.</p></div></section>
    <section id="plans" class="plan-grid"><article v-for="plan in plans" :key="plan.id" :class="[`plan-${plan.accent}`,{featured:plan.is_featured,current:plan.slug===currentPlan}]"><div v-if="plan.is_featured" class="popular"><Sparkles/> MOST POPULAR</div><header><span class="plan-icon"><Rocket v-if="plan.slug==='pro'"/><Crown v-else-if="plan.slug==='elite'"/><ShieldCheck v-else/></span><div><h2>{{plan.name}}</h2><p>{{plan.tagline}}</p></div></header><div class="plan-price"><strong v-if="price(plan)">{{money(monthlyEquivalent(plan))}}</strong><strong v-else>Free</strong><span v-if="price(plan)">/ month</span><small v-if="annual&&price(plan)">Billed {{money(price(plan))}} yearly</small></div><p class="plan-description">{{plan.description}}</p><dl><div><Radio/><dt>Live audience</dt><dd>{{Number(plan.limits.live_viewers).toLocaleString()}}</dd></div><div><Download/><dt>Storage</dt><dd>{{plan.limits.storage_gb}} GB</dd></div><div><Users/><dt>Workspace</dt><dd>{{plan.limits.workspace_seats}} seat{{plan.limits.workspace_seats>1?'s':''}}</dd></div><div><BarChart3/><dt>Analytics</dt><dd>{{plan.limits.analytics_days}} days</dd></div></dl><ul><li v-for="feature in plan.features" :key="feature"><Check/>{{feature}}</li></ul><button v-if="plan.slug===currentPlan" disabled>Current plan</button><button v-else :disabled="saving!==null" @click="changePlan(plan)">{{saving===plan.slug?'Opening PayFast…':plan.monthly_price_cents===0?'Move to Free':`Choose ${plan.name}`}}</button></article></section>
    <section class="membership-trust"><ShieldCheck/><div><strong>Upgrade with confidence</strong><p>Your profile, posts, followers and opportunities stay exactly where they are when changing plans. Free remains genuinely useful—paid plans simply remove ceilings and unlock professional leverage.</p></div></section>
  </main></AppShell>
</template>

